import{_ as a,c as i,o as e,a1 as s}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"クイックスタート：OpenSkillsを始めよう | OpenSkills","description":"OpenSkillsのクイックスタートを学びます。15分以内でツールとスキルのインストールを完了し、AIエージェントが新しいスキルを使用できるようにして、その動作原理を理解します。","frontmatter":{"title":"クイックスタート：OpenSkillsを始めよう | OpenSkills","sidebarTitle":"15分で始める","subtitle":"クイックスタート：OpenSkillsを始めよう | OpenSkills","description":"OpenSkillsのクイックスタートを学びます。15分以内でツールとスキルのインストールを完了し、AIエージェントが新しいスキルを使用できるようにして、その動作原理を理解します。","order":1},"headers":[],"relativePath":"ja/numman-ali/openskills/start/index.md","filePath":"ja/numman-ali/openskills/start/index.md"}'),t={name:"ja/numman-ali/openskills/start/index.md"};function n(r,l,o,h,d,p){return e(),i("div",null,[...l[0]||(l[0]=[s(`<h1 id="クイックスタート" tabindex="-1">クイックスタート <a class="header-anchor" href="#クイックスタート" aria-label="Permalink to &quot;クイックスタート&quot;">​</a></h1><p>このセクションでは、ツールのインストールからAIエージェントがスキルを使用するまで、10〜15分でOpenSkillsを始められるようにします。</p><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>以下の順序で学習することをお勧めします：</p><h3 id="_1-クイックスタート" tabindex="-1">1. <a href="./quick-start/">クイックスタート</a> <a class="header-anchor" href="#_1-クイックスタート" aria-label="Permalink to &quot;1. [クイックスタート](./quick-start/)&quot;">​</a></h3><p>5分以内でツールのインストール、スキルのインストールと同期を完了し、OpenSkillsの核心的な価値を体験します。</p><ul><li>OpenSkillsツールのインストール</li><li>Anthropic公式リポジトリからスキルをインストール</li><li>スキルをAGENTS.mdに同期</li><li>AIエージェントがスキルを使用できることを検証</li></ul><h3 id="_2-openskillsとは何ですか" tabindex="-1">2. <a href="./what-is-openskills/">OpenSkillsとは何ですか？</a> <a class="header-anchor" href="#_2-openskillsとは何ですか" aria-label="Permalink to &quot;2. [OpenSkillsとは何ですか？](./what-is-openskills/)&quot;">​</a></h3><p>OpenSkillsの核心的な概念と動作原理を理解します。</p><ul><li>OpenSkillsとClaude Codeの関係</li><li>統一されたスキルフォーマット、漸進的な読み込み、マルチエージェント対応</li><li>内蔵スキルシステムではなくOpenSkillsを使用すべきタイミング</li></ul><h3 id="_3-インストールガイド" tabindex="-1">3. <a href="./installation/">インストールガイド</a> <a class="header-anchor" href="#_3-インストールガイド" aria-label="Permalink to &quot;3. [インストールガイド](./installation/)&quot;">​</a></h3><p>詳細なインストール手順と環境設定。</p><ul><li>Node.jsとGitの環境チェック</li><li>npxの一時使用 vs グローバルインストール</li><li>よくあるインストール問題のトラブルシューティング</li></ul><h3 id="_4-最初のスキルをインストール" tabindex="-1">4. <a href="./first-skill/">最初のスキルをインストール</a> <a class="header-anchor" href="#_4-最初のスキルをインストール" aria-label="Permalink to &quot;4. [最初のスキルをインストール](./first-skill/)&quot;">​</a></h3><p>Anthropic公式リポジトリからスキルをインストールし、インタラクティブな選択体験をします。</p><ul><li><code>openskills install</code>コマンドを使用</li><li>必要なスキルを対話的に選択</li><li>スキルのディレクトリ構造（.claude/skills/）を理解</li></ul><h3 id="_5-スキルをagents-mdに同期" tabindex="-1">5. <a href="./sync-to-agents/">スキルをAGENTS.mdに同期</a> <a class="header-anchor" href="#_5-スキルをagents-mdに同期" aria-label="Permalink to &quot;5. [スキルをAGENTS.mdに同期](./sync-to-agents/)&quot;">​</a></h3><p>AGENTS.mdファイルを生成し、AIエージェントが利用可能なスキルを認識できるようにします。</p><ul><li><code>openskills sync</code>コマンドを使用</li><li>AGENTS.mdのXMLフォーマットを理解</li><li>同期するスキルを選択し、コンテキストサイズを制御</li></ul><h3 id="_6-スキルを使用する" tabindex="-1">6. <a href="./read-skills/">スキルを使用する</a> <a class="header-anchor" href="#_6-スキルを使用する" aria-label="Permalink to &quot;6. [スキルを使用する](./read-skills/)&quot;">​</a></h3><p>AIエージェントがスキルコンテンツを読み込む方法を学びます。</p><ul><li><code>openskills read</code>コマンドを使用</li><li>スキル検索の4段階の優先順位</li><li>複数のスキルを一度に読み込む</li></ul><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>学習を開始する前に、以下を確認してください：</p><ul><li><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 20.6.0以降がインストールされている</li><li><a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a>がインストールされている（GitHubからスキルをインストールするため）</li><li>少なくとも1つのAIコーディングエージェントがインストールされている（Claude Code、Cursor、Windsurf、Aiderなど）</li></ul><div class="tip custom-block"><p class="custom-block-title">環境のクイックチェック</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # v20.6.0以降が表示される</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # git version x.x.xが表示される</span></span></code></pre></div></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>このセクションを完了したら、次の学習を続けることができます：</p><ul><li><a href="./../platforms/cli-commands/">コマンドの詳細</a>：すべてのコマンドと引数について深く理解</li><li><a href="./../platforms/install-sources/">インストールソースの詳細</a>：GitHub、ローカルパス、プライベートリポジトリからスキルをインストールする方法を学ぶ</li><li><a href="./../advanced/create-skills/">カスタムスキルの作成</a>：独自のスキルを作成</li></ul>`,29)])])}const u=a(t,[["render",n]]);export{k as __pageData,u as default};
